code.C:
#include <stdio.h>
int main() {
    int n;
    scanf("%d", &n);
    int max = 0, curr = 0;
    for (int i = 0; i < n; i++) {
        int a, b;
        scanf("%d %d", &a, &b);
        curr += b - a;
        if (curr > max) max = curr;
    }
    printf("%d\n", max);
    return 0;
}

